using Managers.Base;
using System.IO;
using UnityEngine;
using Data;
using System.Collections.Generic;
using Data.Object.StructureDatas;
using Data.Items;
using Controller;
using UnityEngine.Tilemaps;

namespace Managers
{
    public class SManager : SingletonManagerBase<SManager>
    {
        private const string SaveFileName = "save.json";

        public void SaveGame()
        {
            GameSaveData saveData = new GameSaveData();

            // 게임 플래그 저장
            saveData.gameFlags = GameManager.Instance.GameFlag.GetFlagInList();

            // 타일맵 저장
            saveData.tileDatas = new List<TileData>();
            foreach (var tilemap in GameManager.Instance.tilemaps)
            {
                BoundsInt bounds = tilemap.cellBounds;
                for (int x = bounds.xMin; x < bounds.xMax; x++)
                {
                    for (int y = bounds.yMin; y < bounds.yMax; y++)
                    {
                        Vector3Int pos = new Vector3Int(x, y, 0);
                        TileBase tile = tilemap.GetTile(pos);
                        if (tile != null)
                        {
                            saveData.tileDatas.Add(new TileData { position = pos, tileName = tile.name });
                        }
                    }
                }
            }

            // 플레이어 위치 저장
            saveData.playerPosition = PlayerController.instance.transform.position;

            // 인벤토리 저장
            saveData.inventory = PlayerController.instance.Inventory;

            // JSON으로 저장
            string json = JsonUtility.ToJson(saveData);
            string path = Path.Combine(Application.persistentDataPath, SaveFileName);
            File.WriteAllText(path, json);
        }

        public void LoadGame()
        {
            string path = Path.Combine(Application.persistentDataPath, SaveFileName);
            if (File.Exists(path))
            {
                string json = File.ReadAllText(path);
                GameSaveData saveData = JsonUtility.FromJson<GameSaveData>(json);

                // 게임 플래그 로드
                foreach (var flag in saveData.gameFlags)
                {
                    GameManager.Instance.GameFlag.SetFlag(flag.Key, flag.Value);
                }

                // 타일맵 로드 - 타일맵을 클리어하고 다시 설정
                foreach (var tilemap in GameManager.Instance.tilemaps)
                {
                    tilemap.ClearAllTiles();
                }
                foreach (var tileData in saveData.tileDatas)
                {
                    TileBase tile = Resources.Load<TileBase>(tileData.tileName);
                    if (tile != null)
                    {
                        // tilemap을 찾는 로직 필요. 모든 tilemap에 대해 시도하거나, 특정 tilemap 지정.
                        // 간단히 첫 번째 tilemap에 설정
                        GameManager.Instance.tilemaps[0].SetTile(tileData.position, tile);
                    }
                }

                // 플레이어 위치 로드
                PlayerController.instance.transform.position = saveData.playerPosition;

                // 인벤토리 로드
                PlayerController.instance.Inventory = saveData.inventory;
                GameManager.Instance.InventoryController.items = saveData.inventory;
                GameManager.Instance.InventoryController.Refresh();
            }
        }
    }
}

